Add three new mapping branches to `sdk-event-mapper.ts` to convert SDK task lifecycle messages into DorkOS stream events. Add SDK scenario builders and mapper tests.

## Files to Modify

### 1. `apps/server/src/services/runtimes/claude-code/sdk-event-mapper.ts`

Add three new mapping branches after the existing `system/init` check (line 29, after `return;`) and before the `stream_event` check (line 32). The new code goes between lines 30-31:

```typescript
  // Handle subagent lifecycle messages (task_started, task_progress, task_notification)
  if (message.type === 'system' && 'subtype' in message) {
    if (message.subtype === 'task_started') {
      yield {
        type: 'subagent_started',
        data: {
          taskId: (message as Record<string, unknown>).task_id as string,
          subagentSessionId: message.session_id,
          toolUseId: (message as Record<string, unknown>).tool_use_id as string | undefined,
          description: (message as Record<string, unknown>).description as string,
        },
      };
      return;
    }

    if (message.subtype === 'task_progress') {
      const msg = message as Record<string, unknown>;
      const usage = msg.usage as { tool_uses: number; duration_ms: number };
      yield {
        type: 'subagent_progress',
        data: {
          taskId: msg.task_id as string,
          toolUses: usage.tool_uses,
          lastToolName: msg.last_tool_name as string | undefined,
          durationMs: usage.duration_ms,
        },
      };
      return;
    }

    if (message.subtype === 'task_notification') {
      const msg = message as Record<string, unknown>;
      const usage = msg.usage as { tool_uses: number; duration_ms: number } | undefined;
      yield {
        type: 'subagent_done',
        data: {
          taskId: msg.task_id as string,
          status: msg.status as 'completed' | 'failed' | 'stopped',
          summary: msg.summary as string | undefined,
          toolUses: usage?.tool_uses,
          durationMs: usage?.duration_ms,
        },
      };
      return;
    }
  }
```

**Important placement note:** This block must come AFTER the `system/init` check (lines 19-29) so init messages are still handled first. It must come BEFORE the `stream_event` check (line 32) so task messages don't fall through.

The existing `system/init` check on line 19 uses `message.subtype === 'init'` with a compound condition. The new block handles the three additional subtypes. Other system subtypes (status, compact_boundary, etc.) continue to fall through silently.

### 2. `apps/server/src/services/runtimes/claude-code/__tests__/sdk-scenarios.ts`

Add three new builder functions at the end of the file, before the final closing. Follow the existing pattern of `makeInit`/`makeResult` helpers:

```typescript
const SUBAGENT_UUID = '00000000-0000-4000-8000-000000000099' as `${string}-${string}-${string}-${string}-${string}`;

/**
 * Yield a task_started system message for subagent lifecycle testing.
 *
 * @param taskId - Unique task identifier
 * @param description - User-facing subagent description
 */
export function sdkTaskStarted(taskId: string, description: string): SDKMessage {
  return {
    type: 'system',
    subtype: 'task_started',
    task_id: taskId,
    description,
    session_id: `subagent-${taskId}`,
    uuid: SUBAGENT_UUID,
  } as SDKMessage;
}

/**
 * Yield a task_progress system message for subagent lifecycle testing.
 *
 * @param taskId - Unique task identifier
 * @param toolUses - Number of tool calls made so far
 * @param durationMs - Elapsed time in milliseconds
 * @param lastToolName - Most recently used tool name
 */
export function sdkTaskProgress(
  taskId: string,
  toolUses: number,
  durationMs: number,
  lastToolName?: string,
): SDKMessage {
  return {
    type: 'system',
    subtype: 'task_progress',
    task_id: taskId,
    description: 'test task',
    usage: { total_tokens: 1000, tool_uses: toolUses, duration_ms: durationMs },
    last_tool_name: lastToolName,
    session_id: `subagent-${taskId}`,
    uuid: SUBAGENT_UUID,
  } as SDKMessage;
}

/**
 * Yield a task_notification system message for subagent lifecycle testing.
 *
 * @param taskId - Unique task identifier
 * @param status - Final subagent status
 * @param summary - Subagent completion summary text
 */
export function sdkTaskNotification(
  taskId: string,
  status: 'completed' | 'failed' | 'stopped',
  summary: string,
): SDKMessage {
  return {
    type: 'system',
    subtype: 'task_notification',
    task_id: taskId,
    status,
    output_file: '/tmp/output.txt',
    summary,
    usage: { total_tokens: 2000, tool_uses: 5, duration_ms: 3000 },
    session_id: `subagent-${taskId}`,
    uuid: SUBAGENT_UUID,
  } as SDKMessage;
}
```

### 3. `apps/server/src/services/runtimes/claude-code/__tests__/sdk-event-mapper.test.ts` (NEW FILE)

Create a new test file for the mapper. There is currently no dedicated mapper test file — the existing tests are in `sdk-scenarios.test.ts` which tests the scenario builders, not the mapper itself.

```typescript
import { describe, it, expect } from 'vitest';
import { mapSdkMessage } from '../sdk-event-mapper.js';
import { sdkTaskStarted, sdkTaskProgress, sdkTaskNotification } from './sdk-scenarios.js';
import type { AgentSession, ToolState } from '../agent-types.js';
import type { StreamEvent } from '@dorkos/shared/types';

/** Collect all events yielded by the mapper for a single message. */
async function collectEvents(
  ...args: Parameters<typeof mapSdkMessage>
): Promise<StreamEvent[]> {
  const events: StreamEvent[] = [];
  for await (const event of mapSdkMessage(...args)) {
    events.push(event);
  }
  return events;
}

function makeSession(): AgentSession {
  return {
    sdkSessionId: null,
    hasStarted: false,
  } as AgentSession;
}

function makeToolState(): ToolState {
  return {
    inTool: false,
    currentToolName: '',
    currentToolId: '',
    taskToolInput: '',
    setToolState(inTool: boolean, name: string, id: string) {
      this.inTool = inTool;
      this.currentToolName = name;
      this.currentToolId = id;
    },
    resetTaskInput() {
      this.taskToolInput = '';
    },
    appendTaskInput(chunk: string) {
      this.taskToolInput += chunk;
    },
  } as ToolState;
}

describe('sdk-event-mapper subagent lifecycle', () => {
  const session = makeSession();
  const sessionId = 'test-session';
  const toolState = makeToolState();

  it('maps task_started to subagent_started', async () => {
    const msg = sdkTaskStarted('task-1', 'Explore codebase');
    const events = await collectEvents(msg, session, sessionId, toolState);

    expect(events).toHaveLength(1);
    expect(events[0].type).toBe('subagent_started');
    expect(events[0].data).toEqual({
      taskId: 'task-1',
      subagentSessionId: 'subagent-task-1',
      toolUseId: undefined,
      description: 'Explore codebase',
    });
  });

  it('maps task_progress to subagent_progress', async () => {
    const msg = sdkTaskProgress('task-1', 3, 5000, 'Read');
    const events = await collectEvents(msg, session, sessionId, toolState);

    expect(events).toHaveLength(1);
    expect(events[0].type).toBe('subagent_progress');
    expect(events[0].data).toEqual({
      taskId: 'task-1',
      toolUses: 3,
      lastToolName: 'Read',
      durationMs: 5000,
    });
  });

  it('maps task_progress without lastToolName', async () => {
    const msg = sdkTaskProgress('task-1', 1, 1000);
    const events = await collectEvents(msg, session, sessionId, toolState);

    expect(events).toHaveLength(1);
    expect(events[0].data).toEqual({
      taskId: 'task-1',
      toolUses: 1,
      lastToolName: undefined,
      durationMs: 1000,
    });
  });

  it('maps task_notification (completed) to subagent_done', async () => {
    const msg = sdkTaskNotification('task-1', 'completed', 'Found 7 files');
    const events = await collectEvents(msg, session, sessionId, toolState);

    expect(events).toHaveLength(1);
    expect(events[0].type).toBe('subagent_done');
    expect(events[0].data).toEqual({
      taskId: 'task-1',
      status: 'completed',
      summary: 'Found 7 files',
      toolUses: 5,
      durationMs: 3000,
    });
  });

  it('maps task_notification (failed) to subagent_done', async () => {
    const msg = sdkTaskNotification('task-1', 'failed', 'Error occurred');
    const events = await collectEvents(msg, session, sessionId, toolState);

    expect(events).toHaveLength(1);
    expect(events[0].type).toBe('subagent_done');
    expect(events[0].data).toMatchObject({
      taskId: 'task-1',
      status: 'failed',
      summary: 'Error occurred',
    });
  });

  it('yields nothing for unknown system subtypes', async () => {
    const msg = {
      type: 'system',
      subtype: 'status',
      session_id: 'test',
      uuid: '00000000-0000-4000-8000-000000000001',
    } as unknown as Parameters<typeof mapSdkMessage>[0];
    const events = await collectEvents(msg, session, sessionId, toolState);

    expect(events).toHaveLength(0);
  });
});
```

