              isActive={isActive}
              onDecided={onToolDecided ? () => onToolDecided(part.toolCallId) : undefined}
            />
          );
        }
        if (part.interactiveType === 'question' && part.questions) {
          const isActive = part.toolCallId === activeToolCallId;
          return (
            <QuestionPrompt
              key={part.toolCallId}
              ref={isActive ? questionRefCallback : undefined}
              sessionId={sessionId}
              toolCallId={part.toolCallId}
              questions={part.questions}
              answers={part.answers}
              isActive={isActive}
              focusedOptionIndex={isActive ? focusedOptionIndex : -1}
            />
          );
        }
        if (part.type === 'subagent') {
          return <SubagentBlock key={part.taskId} part={part} />;
        }
        return (
          <AutoHideToolCall
            key={part.toolCallId}
            part={part}
            autoHide={autoHideToolCalls}
            expandToolCalls={expandToolCalls}
          />
        );
      })}
```

## Important Notes

- **No auto-hide behavior** for SubagentBlock — subagent blocks are high-signal lifecycle indicators and should remain permanently visible. They don't use the `AutoHideToolCall` wrapper.
- **React key** uses `part.taskId` (not an index) because `taskId` is already unique from the SDK (it's the task's UUID assigned by Claude). This is different from text parts which use `_partId` and tool calls which use `toolCallId`.
- The `part.type === 'subagent'` check must come BEFORE the `AutoHideToolCall` fallback. Since the `MessagePartSchema` discriminated union now includes `SubagentPartSchema`, TypeScript knows about the `'subagent'` type, but the existing code's fallback branch assumes all non-text parts are tool calls. Without this early return, SubagentParts would hit the `AutoHideToolCall` component and fail because they don't have `toolCallId`, `toolName`, etc.
- The `interactiveType` checks (lines 129, 144) access properties that only exist on `ToolCallPart`, not on `SubagentPart`. Since TypeScript narrows the type after the `part.type === 'text'` check, accessing `part.interactiveType` when `part.type === 'subagent'` would be a type error. However, the `interactiveType` checks are guarded by their own `if` conditions and SubagentParts don't have `interactiveType`, so they'll fall through to the subagent check.

